// Barrel for the BTCarousel organism.
export 'carousel.types.dart';
export 'carousel.widget.dart';

/// BTCarousel type definitions.
///
/// Figma: node 2344-1404 (D-Carousel).
library;

/// Layout direction for [BTCarousel].
enum BTCarouselVariant {
  /// Slides scroll left / right; prev/next buttons on sides.
  horizontal,

  /// Slides scroll up / down; prev/next buttons above/below.
  vertical,
}

/// BTCarousel — horizontal or vertical sliding carousel.
///
/// Figma: node 2344-1404 (D-Carousel).
///
/// Uses [PageView.builder] for native physics-based swiping on mobile.
/// Navigation buttons appear outside the slide viewport (left/right for
/// horizontal, top/bottom for vertical). Dot indicators are overlaid at
/// the bottom of the viewport.
///
/// ## Usage:
/// ```dart
/// // Horizontal (default)
/// BTCarousel.horizontal(
///   itemCount: images.length,
///   itemBuilder: (context, index) => Image.network(
///     images[index],
///     fit: BoxFit.cover,
///     width: double.infinity,
///   ),
/// )
///
/// // Vertical
/// BTCarousel.vertical(
///   itemCount: 5,
///   initialIndex: 2,
///   onPageChanged: (index) => print('Slide $index'),
///   itemBuilder: (context, index) => Container(
///     color: Colors.primaries[index % Colors.primaries.length],
///     child: Center(child: Text('Slide $index')),
///   ),
/// )
///
/// // Controlled (external page controller)
/// BTCarousel.horizontal(
///   itemCount: 4,
///   controller: _myController,
///   showIndicators: false,
///   itemBuilder: (context, index) => _buildSlide(index),
/// )
/// ```
library;

import 'dart:async';

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import 'package:btech_ui/src/components/organisms/carousel/carousel.types.dart';
import 'package:flutter/material.dart';

/// Sliding carousel organism.
///
/// See file header for usage examples.
class BTCarousel extends StatefulWidget {
  /// Horizontal carousel — slides scroll left / right.
  const BTCarousel.horizontal({
    required this.itemCount,
    required this.itemBuilder,
    super.key,
    this.controller,
    this.initialIndex = 0,
    this.onPageChanged,
    this.loop = false,
    this.showButtons = true,
    this.showIndicators = true,
    this.autoPlayInterval,
  }) : variant = BTCarouselVariant.horizontal;

  /// Vertical carousel — slides scroll up / down.
  const BTCarousel.vertical({
    required this.itemCount,
    required this.itemBuilder,
    super.key,
    this.controller,
    this.initialIndex = 0,
    this.onPageChanged,
    this.loop = false,
    this.showButtons = true,
    this.showIndicators = true,
    this.autoPlayInterval,
  }) : variant = BTCarouselVariant.vertical;

  /// Layout direction.
  final BTCarouselVariant variant;

  /// Total number of slides.
  final int itemCount;

  /// Builder called for each slide index.
  final Widget Function(BuildContext context, int index) itemBuilder;

  /// External [PageController]. When provided, the carousel is controlled
  /// externally; internal controller is not created.
  final PageController? controller;

  /// Slide index shown on first render. Ignored when [controller] is provided.
  /// @default 0
  final int initialIndex;

  /// Called whenever the visible page changes.
  final void Function(int index)? onPageChanged;

  /// Loop back to the first/last slide at boundaries.
  /// @default false
  final bool loop;

  /// Show previous / next navigation buttons. @default true
  final bool showButtons;

  /// Show dot indicators at the bottom of the viewport. @default true
  final bool showIndicators;

  /// When set, automatically advances to the next slide at this interval.
  /// Stops at the last slide when [loop] is `false`.
  /// Example: `autoPlayInterval: const Duration(seconds: 3)`
  /// @default null (disabled)
  final Duration? autoPlayInterval;

  @override
  State<BTCarousel> createState() => _BTCarouselState();
}

class _BTCarouselState extends State<BTCarousel> {
  late PageController _controller;
  bool _ownsController = false;
  int _currentPage = 0;
  Timer? _autoPlayTimer;

  @override
  void initState() {
    super.initState();
    if (widget.controller != null) {
      _controller = widget.controller!;
    } else {
      _controller = PageController(
        initialPage: widget.initialIndex,
        // Shows ~6 % of each adjacent slide on both edges.
        viewportFraction: 0.88,
      );
      _ownsController = true;
    }
    _currentPage = widget.initialIndex;
    _startAutoPlay();
  }

  @override
  void didUpdateWidget(BTCarousel oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.autoPlayInterval != widget.autoPlayInterval) {
      _stopAutoPlay();
      _startAutoPlay();
    }
  }

  @override
  void dispose() {
    _stopAutoPlay();
    if (_ownsController) _controller.dispose();
    super.dispose();
  }

  void _startAutoPlay() {
    final interval = widget.autoPlayInterval;
    if (interval == null) return;
    _autoPlayTimer = Timer.periodic(interval, (_) {
      if (!mounted) return;
      if (_atEnd) return; // non-loop: stay on last slide
      _next();
    });
  }

  void _stopAutoPlay() {
    _autoPlayTimer?.cancel();
    _autoPlayTimer = null;
  }

  void _goTo(int index) {
    var target = index;
    if (widget.loop) {
      target = ((index % widget.itemCount) + widget.itemCount) % widget.itemCount;
    } else {
      target = index.clamp(0, widget.itemCount - 1);
    }
    _controller.animateToPage(
      target,
      duration: const Duration(milliseconds: 350),
      curve: Curves.easeInOut,
    );
  }

  void _prev() => _goTo(_currentPage - 1);
  void _next() => _goTo(_currentPage + 1);

  bool get _atStart => !widget.loop && _currentPage == 0;
  bool get _atEnd   => !widget.loop && _currentPage >= widget.itemCount - 1;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;

    final isHorizontal = widget.variant == BTCarouselVariant.horizontal;
    final isRtl = isHorizontal &&
        Directionality.of(context) == TextDirection.rtl;

    final pageView = PageView.builder(
      controller: _controller,
      scrollDirection: isHorizontal ? Axis.horizontal : Axis.vertical,
      physics: widget.loop
          ? const PageScrollPhysics()
          : const PageScrollPhysics(),
      itemCount: widget.loop ? null : widget.itemCount,
      onPageChanged: (page) {
        final realIndex = widget.loop ? page % widget.itemCount : page;
        setState(() => _currentPage = realIndex);
        widget.onPageChanged?.call(realIndex);
      },
      itemBuilder: (ctx, index) {
        final realIndex = widget.loop ? index % widget.itemCount : index;
        // Add 2px padding on each side → 4px visible gap between slides.
        return Padding(
          padding: isHorizontal
              ? const EdgeInsets.symmetric(horizontal: 2)
              : const EdgeInsets.symmetric(vertical: 2),
          child: widget.itemBuilder(ctx, realIndex),
        );
      },
    );

    // ── Viewport with indicators overlaid ──────────────────────────
    final viewport = Stack(
      children: [
        Positioned.fill(child: pageView),
        if (widget.showIndicators && widget.itemCount > 1)
          Positioned(
            bottom: 8,
            left: 0,
            right: 0,
            child: _BTCarouselIndicators(
              count: widget.itemCount,
              activeIndex: _currentPage,
              activeColor: c.brand.primary,
              inactiveColor: c.icon.tertiary,
            ),
          ),
      ],
    );

    // ── Prev button — BTButton.secondaryLight wrapped to be circular ────
    final prevBtn = Semantics(
      button: true,
      label: isHorizontal ? 'Previous slide' : 'Previous',
      enabled: !_atStart,
      child: ClipRRect(
        borderRadius: BorderRadius.circular(9999),
        child: BTButton.iconOnly(
          icon: Icon(
            isHorizontal
                ? (isRtl ? Icons.chevron_right : Icons.chevron_left)
                : Icons.keyboard_arrow_up,
          ),
          onPressed: _atStart ? null : _prev,
          variant: BTButtonVariant.secondaryLight,
          size: BTButtonSize.sm,
        ),
      ),
    );

    // ── Next button — BTButton.secondaryLight wrapped to be circular ────
    final nextBtn = Semantics(
      button: true,
      label: isHorizontal ? 'Next slide' : 'Next',
      enabled: !_atEnd,
      child: ClipRRect(
        borderRadius: BorderRadius.circular(9999),
        child: BTButton.iconOnly(
          icon: Icon(
            isHorizontal
                ? (isRtl ? Icons.chevron_left : Icons.chevron_right)
                : Icons.keyboard_arrow_down,
          ),
          onPressed: _atEnd ? null : _next,
          variant: BTButtonVariant.secondaryLight,
          size: BTButtonSize.sm,
        ),
      ),
    );

    // 4px gap between nav buttons and viewport — matches web gap: 4px.
    const gap = 4.0;

    if (isHorizontal) {
      return Row(
        children: [
          if (widget.showButtons) ...[
            prevBtn,
            const SizedBox(width: gap),
          ],
          Expanded(child: viewport),
          if (widget.showButtons) ...[
            const SizedBox(width: gap),
            nextBtn,
          ],
        ],
      );
    } else {
      return Column(
        children: [
          if (widget.showButtons) ...[
            prevBtn,
            const SizedBox(height: gap),
          ],
          Expanded(child: viewport),
          if (widget.showButtons) ...[
            const SizedBox(height: gap),
            nextBtn,
          ],
        ],
      );
    }
  }
}

// ── Private sub-widgets ───────────────────────────────────────────────

/// Row of dot indicator dots.
class _BTCarouselIndicators extends StatelessWidget {
  const _BTCarouselIndicators({
    required this.count,
    required this.activeIndex,
    required this.activeColor,
    required this.inactiveColor,
  });

  final int count;
  final int activeIndex;
  final Color activeColor;
  final Color inactiveColor;

  @override
  Widget build(BuildContext context) {
    return Row(
      mainAxisAlignment: MainAxisAlignment.center,
      children: List.generate(count, (i) {
        final isActive = i == activeIndex;
        return AnimatedContainer(
          duration: const Duration(milliseconds: 220),
          curve: Curves.easeInOut,
          margin: const EdgeInsets.symmetric(horizontal: 1),
          width: isActive ? 12 : 4,
          height: 4,
          decoration: BoxDecoration(
            color: isActive ? activeColor : inactiveColor,
            borderRadius: BorderRadius.circular(8),
          ),
        );
      }),
    );
  }
}
